  ('optometrist-moex-00186', 'optometrist', 'optometrist-moex-114-ddcf1380', 'sub-optometrist-04', NULL, 'single_choice', '當用隱形眼鏡校正眼睛的遠距視力時，與眼鏡相比，需要多少調節能力才能聚焦近處物體的圖像？', '["隱形眼鏡降低了近視眼的調節需求", "隱形眼鏡降低了遠視眼的調節需求", "隱形眼鏡不會改變近視眼的調節需求", "隱形眼鏡增加了遠視眼的調節需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "2a988593012e", "answer_pdf_sha1": "7a79b7c373e7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視覺光學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
